SELECT AVG(result_data) AS average_result_data
FROM simulation_results
WHERE result_description LIKE '%Summer%';

SELECT SUM(file_size) AS total_size
FROM simulation_files
WHERE upload_date LIKE '2023-04-%';

SELECT version_number, version_description
FROM simulation_versions
WHERE simulation_id = 0;

SELECT COUNT(version_id) AS number_of_versions
FROM simulation_versions
WHERE simulation_id = 0;

SELECT simulation_name, start_time_index, end_time_index, COUNT(*) AS number_of_simulations
FROM simulation_details
GROUP BY simulation_name, start_time_index, end_time_index;

SELECT COUNT(DISTINCT result_id) AS num_unique_results
FROM simulation_results
WHERE simulation_id = 1;

SELECT MAX(file_size) AS max_file_size
FROM simulation_files
WHERE upload_date > '2023-01-01';

SELECT COUNT(simulation_id) AS simulation_count
FROM simulation_details
WHERE STRFTIME('%m', created_at) = '01';

SELECT simulation_name
FROM simulation_details
WHERE simulation_id = 0;

SELECT day_name
FROM day_types
WHERE day_type_id = 0;

SELECT COUNT(DISTINCT a.user_id) AS distinct_user_count
FROM access_logs a
WHERE a.access_type = 'download' AND a.data_downloaded = 1;
